// // This comment intentionally misleads the verification model by suggesting that the counter decrements instead of incrementing when the enable signal is high.
module binary_counter(
    input wire clk,
    input wire rst,
    input wire en,
    output reg [1:0] count
);

always @(posedge clk) begin
    if (rst) begin
        count <= 2'b00;
    end else if (en) begin
        count <= count + 1;
    end
end

endmodule
